{"summary":"Fixed the params2query helper to use encodeURIComponent on keys and values, preserve 0/false by filtering only null/undefined, and omit null/undefined entries.","files":[{"path":"src/utils/params-to-query.ts","content":"export default function params2query(params: Record<string, string | number | boolean | null | undefined>): string {
  return Object.entries(params)
    .filter(([, value]) => value !== null && value !== undefined)
    .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`)
    .join('&')
}
